const prompt = (id, text, participantCount) => ({
  id,
  text,
  ...(participantCount ? { participantCount } : {}),
});

const story = (title, intro, prompts, template) => ({
  title,
  intro,
  prompts,
  template,
});

// Omit `participantCount` for a whole-group prompt.
const commonPrompts = [
  prompt('packedSnack', 'a favorite snack everyone would pack'),
  prompt('firstJob', 'the first job they ever had', 1),
  prompt('sharedHobby', 'a secret hobby they could teach each other', 2),
  prompt('outfitAdjective', 'an adjective that describes both of their outfits today', 2),
  prompt('teamName', 'a silly team name'),
  prompt('sharedDestination', 'a place they would happily visit together', 2),
  prompt('adventureSupply', 'something they would both bring on an adventure', 2),
  prompt('singalongSong', 'a favorite song they would sing along to together', 2),
  prompt('mysteriousObject', 'a mysterious object'),
  prompt('groupAdjective', 'an adjective that describes the group', 2),
  prompt('groupShowcase', 'a place they would like to show the group', 2),
  prompt('celebrationFood', 'a celebratory food'),
  prompt('dramaticSound', 'a dramatic sound effect'),
  prompt('sharedAmbition', 'a childhood ambition they had in common', 2),
  prompt('victoryVerb', 'a verb for a victory dance', 2),
  prompt('mascotAnimal', 'a mascot animal'),
  prompt('sharedSkill', 'a little-known skill they have', 2),
  prompt('scenicDestination', 'a scenic destination', 1),
  prompt('unnecessaryRule', 'a completely unnecessary rule', 1),
  prompt('codeWord', 'a secret code word'),
];

const stories = [
  story(
    'The Unexpected Adventure',
    'Your group has been selected for an extremely important mission.',
    [
      ...commonPrompts,
      prompt('missionWeather', 'an adjective for the mission weather', 2),
      prompt('missionTool', 'a tool from a past job that would help this mission', 1),
      prompt('workshopArtifact', 'a strange artifact from the hidden workshop', 2),
      prompt('missionReward', 'a reward for completing the mission'),
      prompt('adventureChapter', 'a title for this adventure chapter', 2),
      prompt('adventureCelebration', 'a way the team would celebrate after saving the day', 2),
      prompt('getawayVehicle', 'an unusual vehicle for the getaway'),
      prompt('missionAdvice', 'a piece of advice for the mission leader', 1),
      prompt('victoryPhotoPose', 'a pose for the team’s victory photo', 2),
      prompt('legendClosing', 'a closing phrase for the legend'),
    ],
    'At breakfast, the {{teamName}} received an urgent message: the world’s supply of {{packedSnack}} had ' +
      'vanished. {{firstJob}}, once a {{sharedHobby}}, found a {{outfitAdjective}} clue pointing to ' +
      '{{sharedDestination}}. The team packed {{adventureSupply}}, sang {{singalongSong}}, and discovered a ' +
      '{{mysteriousObject}} beneath a {{groupAdjective}} cloud. At {{groupShowcase}}, they were served ' +
      '{{celebrationFood}} by a machine that went "{{dramaticSound}}." Its inventor dreamed of becoming ' +
      '{{sharedAmbition}} and asked everyone to {{victoryVerb}} with the {{mascotAnimal}}. Using {{sharedSkill}}, ' +
      'they reached {{scenicDestination}}, ignored {{unnecessaryRule}}, and said "{{codeWord}}" at the door. ' +
      'The {{missionWeather}} weather revealed {{missionTool}} beside {{workshopArtifact}}, plus a ' +
      '{{missionReward}} labeled "{{adventureChapter}}." After {{adventureCelebration}}, they boarded ' +
      '{{getawayVehicle}}. With {{missionAdvice}} in mind, they struck {{victoryPhotoPose}} and declared: ' +
      '"{{legendClosing}}"'
  ),
  story(
    'The Legendary Talent Show',
    'Your group is about to become unexpectedly famous.',
    [
      ...commonPrompts,
      prompt('stageLights', 'an adjective for the stage lights', 2),
      prompt('prizePurchase', 'the first thing they would buy with a talent-show prize', 1),
      prompt('performanceProp', 'an unexpected prop for the performance', 2),
      prompt('judgePrize', 'a surprise prize from the judges'),
      prompt('encoreTitle', 'a title for the encore', 2),
      prompt('afterShowPlan', 'a way the group would spend a free afternoon after the show', 2),
      prompt('castExitVehicle', 'an unusual vehicle for the cast exit'),
      prompt('performerAdvice', 'a piece of advice for a nervous performer', 1),
      prompt('curtainCallPose', 'a pose for the final curtain call', 2),
      prompt('audienceClosing', 'a closing phrase for the audience'),
    ],
    'The {{teamName}} arrived at the talent show with {{packedSnack}} in hand. {{firstJob}}, formerly a ' +
      '{{sharedHobby}}, wore a {{outfitAdjective}} costume inspired by {{sharedDestination}}. ' +
      '{{adventureSupply}} set the mood while {{singalongSong}} became the opening anthem. Then a ' +
      '{{mysteriousObject}} rolled onstage through {{groupAdjective}} fog, carrying tickets to ' +
      '{{groupShowcase}} and a tray of {{celebrationFood}}. It made a {{dramaticSound}} noise, promised ' +
      '{{sharedAmbition}} fame, and asked the dancers to {{victoryVerb}} beside a {{mascotAnimal}}. The judges ' +
      'admired {{sharedSkill}}, awarded a trip to {{scenicDestination}}, and enforced {{unnecessaryRule}} before ' +
      'whispering "{{codeWord}}." In {{stageLights}} weather, {{prizePurchase}} became the grand prize, along ' +
      'with {{performanceProp}} and {{judgePrize}}. The finale was titled "{{encoreTitle}}," involved ' +
      '{{afterShowPlan}}, and departed by {{castExitVehicle}}. Following {{performerAdvice}}, the cast struck ' +
      '{{curtainCallPose}} and shouted "{{audienceClosing}}"'
  ),
  story(
    'The Time Capsule Mix-Up',
    'Your group has uncovered a very peculiar message from the future.',
    [
      ...commonPrompts,
      prompt('futureSky', 'an adjective for a future-day sky', 2),
      prompt('futureFind', 'the first thing they would bring back from the future', 1),
      prompt('futureSouvenir', 'an odd souvenir from tomorrow', 2),
      prompt('futureGift', 'a surprise gift from future-you'),
      prompt('timeTravelChapter', 'a title for this time-travel chapter', 2),
      prompt('futurePastime', 'a favorite future pastime to try together', 2),
      prompt('timeMachineVehicle', 'an unusual time machine vehicle'),
      prompt('futureAdvice', 'a piece of advice from the future', 1),
      prompt('timeTravelPose', 'a pose for the time-travel photo', 2),
      prompt('futureClosing', 'a closing phrase for future-you'),
    ],
    'A time capsule from the {{teamName}} era appeared beside {{packedSnack}}. Its note, written by ' +
      '{{firstJob}}, mentioned {{sharedHobby}} and a {{outfitAdjective}} portal near {{sharedDestination}}. ' +
      'Inside were {{adventureSupply}}, a recording of {{singalongSong}}, and a {{mysteriousObject}} marked ' +
      '"{{groupAdjective}}." The map led to {{groupShowcase}}, where the future served {{celebrationFood}} and ' +
      'greeted visitors with "{{dramaticSound}}." A child who wanted to be {{sharedAmbition}} taught the crew to ' +
      '{{victoryVerb}} with a {{mascotAnimal}}. They needed {{sharedSkill}} to reach {{scenicDestination}}, but ' +
      '{{unnecessaryRule}} slowed the clock until they used the code "{{codeWord}}." Outside, {{futureSky}} skies ' +
      'covered {{futureFind}}, {{futureSouvenir}}, and a {{futureGift}} from tomorrow. The message called this ' +
      'chapter "{{timeTravelChapter}}" and recommended {{futurePastime}}. They left in {{timeMachineVehicle}}, ' +
      'remembered {{futureAdvice}}, posed {{timeTravelPose}}, and signed off: "{{futureClosing}}"'
  ),
  story(
    'The Neighborhood Mystery',
    'Your group has been recruited to solve a charmingly low-stakes mystery.',
    [
      ...commonPrompts,
      prompt('mysteryWeather', 'an adjective for the mystery weather', 2),
      prompt('crimeSceneClue', 'the first thing they would inspect at a crime scene', 1),
      prompt('culpritItem', 'a strange item left by the culprit', 2),
      prompt('mysteryReward', 'a reward for solving the mystery'),
      prompt('caseFileTitle', 'a title for the detective case file', 2),
      prompt('caseCelebration', 'a favorite way to celebrate a solved case', 2),
      prompt('chaseVehicle', 'an unusual vehicle for the detective chase'),
      prompt('detectiveAdvice', 'a piece of advice for a rookie detective', 1),
      prompt('detectivePhotoPose', 'a pose for the detective team photo', 2),
      prompt('caseReportClosing', 'a closing phrase for the case report'),
    ],
    'The {{teamName}} were called when all {{packedSnack}} disappeared from the festival. {{firstJob}}, who ' +
      'once worked as {{sharedHobby}}, noticed a {{outfitAdjective}} footprint leading toward ' +
      '{{sharedDestination}}. {{adventureSupply}} was left at the scene beside a speaker playing ' +
      '{{singalongSong}} and a {{mysteriousObject}} covered in {{groupAdjective}} dust. At {{groupShowcase}}, ' +
      'the suspects were enjoying {{celebrationFood}} when a clue made a {{dramaticSound}} sound. Someone who ' +
      'dreamed of {{sharedAmbition}} had taught the culprit to {{victoryVerb}} with a {{mascotAnimal}}. The trail ' +
      'required {{sharedSkill}}, passed through {{scenicDestination}}, and broke {{unnecessaryRule}} until the ' +
      'team said "{{codeWord}}." In {{mysteryWeather}} weather, they found {{crimeSceneClue}}, {{culpritItem}}, ' +
      'and a {{mysteryReward}} beneath a sign reading "{{caseFileTitle}}." After {{caseCelebration}}, they ' +
      'pursued the culprit by {{chaseVehicle}}. Remembering {{detectiveAdvice}}, the detectives struck ' +
      '{{detectivePhotoPose}} and announced "{{caseReportClosing}}"'
  ),
];

export default stories;
